        "+    frame.push_back(static_cast<uint8_t>((msgType >> 8) & 0xFF));",
        "+    frame.push_back(static_cast<uint8_t>(payloadLen & 0xFF));",
        "+    frame.push_back(static_cast<uint8_t>((payloadLen >> 8) & 0xFF));",
        "+    if (payload && payloadLen > 0) {",
