static bool ParseEndpoint(const char* addrStr, uint16_t port, NetEndpoint* out) {
    if (!out) return false;
    unsigned a = 0, b = 0, c = 0, d = 0;
    char dummy;
    if (sscanf(addrStr, "%u.%u.%u.%u%c", &a, &b, &c, &d, &dummy) == 4) {
        if (a > 255 || b > 255 || c > 255 || d > 255) return false;
