        out->address[1] = static_cast<uint8_t>(b);
        out->address[2] = static_cast<uint8_t>(c);
        out->address[3] = static_cast<uint8_t>(d);
        out->port = port;
        return true;
    }
    if (strcmp(addrStr, "0.0.0.0") == 0 || strcmp(addrStr, "") == 0) {
        *out = NetEndpoint::Any(port);
        return true;
    }
    return false;
}

