std::unique_ptr<NetworkMessage> NetworkLayer::Receive() {
    std::lock_guard<std::mutex> lock(recvMutex_);
    if (recvQueue_.empty()) return nullptr;
    auto msg = std::move(recvQueue_.front());
    recvQueue_.pop_front();
    return msg;
}

