        "-void NetworkLayer::ProcessKcpRcv() {",
        "-    if (isServer_) return; // Server doesn't use KCP",
        "-",
        "-    if (!clientKcp_) return;",
        "-",
        "-    // Keep reading from KCP until there's no more data available",
        "-    int peekSize = clientKcp_->PeekSize();",
        "-    while (peekSize > 0) {",
        "-        int bufSize = std::min(peekSize, static_cast<int>(kcpInputBuf_.size()));",
        "-        int n = clientKcp_->Recv(kcpInputBuf_.data(), bufSize);",
        "-        if (n <= 0) break;",
        "-",
        "-        uint16_t msgType = 0;",
        "-        std::vector<uint8_t> payload;",
        "-        if (Unframe(kcpInputBuf_.data(), static_cast<size_t>(n), msgType, payload)) {",
        "-            HandleIncomingFrame(kcpInputBuf_.data(), static_cast<size_t>(n), 0);",
        "-        }",
        "-",
        "-        peekSize = clientKcp_->PeekSize();",
        "-    }",
        "-}",
