        "-            clientKcp_->Send(it->payload.data(), static_cast<int>(it->payload.size()));",
        "-            it->sentAt = now;",
        "-            it->retries++;",
        "-            retransmits_++;",
        "-        } else {",
        "-            ++it;",
        "-        }",
        "-    }",
