        "+// -- Main update loop --",
        "+",
        "+void NetworkLayer::Update() {",
        "+    if (!udp_ || closing_.load()) return;",
        "+",
        "+    uint64_t now = NowTickMS();",
        "+",
        "+    // 1. Receive UDP datagrams",
        "+    ProcessUDPRcv();",
        "+",
        "+    // 2. KCP update and data extraction (client mode only)",
        "+    if (!isServer_ && clientKcp_) {",
        "+        clientKcp_->Update(static_cast<uint32_t>(now));",
        "+        ProcessKcpRcv();",
        "+    }",
        "+",
        "+    // 3. Flush retransmissions (client mode only)",
        "+    FlushRetransmits();",
        "+",
        "+    // 4. Heartbeat",
        "+    if (now - lastHeartbeatTick_ >= HEARTBEAT_INTERVAL_MS) {",
        "+        SendHeartbeat();",
        "+    }",
        "+    CheckHeartbeatTimeout();",
        "+}",
