        "+bool NetworkLayer::Send(std::unique_ptr<NetworkMessage> msg, uint32_t playerId) {",
        "+    if (!msg) return false;",
        "+",
        "+    std::vector<uint8_t> payload;",
        "+    msg->Serialize(payload);",
        "+",
        "+    std::vector<uint8_t> frame;",
        "+    BuildFrame(msg->GetType(), payload.data(), payload.size(), frame);",
        "+",
        "+    if (isServer_) {",
        "+        // Server mode: find target endpoint by playerId and send directly via UDP",
        "+        auto it = playerIdToEndpoint_.find(playerId);",
        "+        if (it != playerIdToEndpoint_.end()) {",
        "+            int rc = udp_.SendTo(frame.data(), static_cast<int>(frame.size()), it->second);",
        "+            if (rc > 0) bytesSent_ += static_cast<uint64_t>(rc);",
        "+            msgsSent_++;",
        "+            return rc > 0;",
        "+        }",
        "+        // Fallback: send to last known peer (playerId == 0 means broadcast/last peer)",
        "+        if (playerId == 0 && !peerEndpoint_.port) return false;",
        "+        if (playerId == 0) {",
        "+            int rc = udp_.SendTo(frame.data(), static_cast<int>(frame.size()), peerEndpoint_);",
        "+            if (rc > 0) bytesSent_ += static_cast<uint64_t>(rc);",
        "+            msgsSent_++;",
        "+            return rc > 0;",
        "+        }",
        "+        return false;",
        "+    }",
        "+",
        "+    // Client mode: use KCP for reliable transport",
        "+    if (!clientKcp_) return false;",
        "+",
        "+    // Track in send queue for retransmission",
        "+    OutgoingMessage om;",
        "+    om.type = msg->GetType();",
        "+    om.payload = std::move(frame);",
        "+    om.seq = nextSeqOut_++;",
        "+    om.sentAt = NowTickMS();",
        "+    om.retries = 0;",
        "+    sendQueue_.push_back(std::move(om));",
        "+",
        "+    // Send immediately into KCP",
        "+    int rc = clientKcp_->Send(om.payload.data(), static_cast<int>(om.payload.size()));",
        "+    (void)rc;",
        "+",
        "+    msgsSent_++;",
        "+    return true;",
        "+}",
