        "+        std::cerr << "[PhysicsServer] Failed to create server socket on port "",
        "+                  << config_.listenPort << std::endl;",
        "+        return false;",
        "+    }",
        "+",
        "+    std::cout << "[PhysicsServer] Server socket listening on port "",
        "+              << config_.listenPort << std::endl;",
        "+",
        "+    std::cout << "[PhysicsServer] Initialization complete." << std::endl;",
        "+    return true;",
