        "+    if (simulationThread_ && simulationThread_->joinable()) {",
        "+        simulationThread_->join();",
        "+    }",
        "+    if (networkThread_ && networkThread_->joinable()) {",
        "+        networkThread_->join();",
        "+    }",
        "+",
        "+    networkLayer_.Close();",
