void NetworkLayer::Update() {
    if (!udp_ || closing_.load()) return;

    uint64_t now = NowTickMS();

    // 1. Receive UDP datagrams and parse frames
    ProcessUDPRcv();

    // 2. Flush retransmissions (client mode only, no KCP)
    FlushRetransmits();

