        "+    uint64_t now = NowTickMS();",
        "+",
        "+    // 1. Receive UDP datagrams and process through KCP",
        "+    ProcessUDPRcv();",
        "+",
        "+    // 2. Client: KCP update and data extraction",
        "+    if (!isServer_ && clientKcp_) {",
        "+        clientKcp_->Update(static_cast<uint32_t>(now));",
        "+        ProcessKcpRcv();",
        "+    }",
        "+",
        "+    // 3. Server: extract frames from KCP",
        "+    if (isServer_ && kcp_) {",
        "+        ProcessKcpRcv();",
        "+    }",
        "+",
        "+    // 4. Heartbeat",
        "+    if (now - lastHeartbeatTick_ >= HEARTBEAT_INTERVAL_MS) {",
