        "-            uint64_t sentTime = ping->timestamp;",
        "-            float rtt = static_cast<float>(NowTickMS() - sentTime);",
        "-            if (rtt > 0 && rttMs_ == 0) {",
        "-                rttMs_ = rtt;",
