        "+void NetworkLayer::ProcessUDPRcv() {",
        "+    while (udp_.HasData()) {",
        "+        int n = udp_.ReceiveFrom(kcpInputBuf_.data(),",
        "+                                  static_cast<int>(kcpInputBuf_.size()),",
        "+                                  &peerEndpoint_);",
        "+        if (n <= 0) break;",
        "+",
        "+        bytesRcvd_ += static_cast<uint64_t>(n);",
        "+        lastRcvTimeTick_ = NowTickMS();",
        "+",
        "+        // Track peer",
        "+        if (isServer_) {",
        "+            serverPeerCount_++;",
        "+            // Store endpoint for this peer",
        "+            if (!endpointToPlayerId_.count(peerEndpoint_)) {",
        "+                uint32_t pid = nextPlayerId_++;",
        "+                playerIdToEndpoint_[pid] = peerEndpoint_;",
        "+                endpointToPlayerId_[peerEndpoint_] = pid;",
        "+            }",
        "+        }",
        "+",
        "+        // Client: feed UDP into client KCP",
        "+        if (!isServer_ && clientKcp_) {",
        "+            clientKcp_->Input(kcpInputBuf_.data(), n);",
        "+        }",
        "+",
        "+        // Server: feed UDP into server KCP",
        "+        if (isServer_ && kcp_) {",
        "+            kcp_->Input(kcpInputBuf_.data(), n);",
        "+        }",
        "+    }",
        "+}",
