        "+    if (!isServer_ && clientKcp_) {",
        "+        peekSize = clientKcp_->PeekSize();",
        "+    } else if (isServer_ && kcp_) {",
        "+        peekSize = kcp_->PeekSize();",
        "+    }",
        "+",
        "+    while (peekSize > 0) {",
        "+        int bufSize = std::min(peekSize, static_cast<int>(kcpInputBuf_.size()));",
        "+        int n = 0;",
        "+        if (!isServer_ && clientKcp_) {",
        "+            n = clientKcp_->Recv(kcpInputBuf_.data(), bufSize);",
        "+        } else if (isServer_ && kcp_) {",
        "+            n = kcp_->Recv(kcpInputBuf_.data(), bufSize);",
        "+        }",
        "+        if (n <= 0) break;",
        "+",
        "+        uint16_t msgType = 0;",
        "+        std::vector<uint8_t> payload;",
        "+        if (Unframe(kcpInputBuf_.data(), static_cast<size_t>(n), msgType, payload)) {",
        "+            HandleIncomingFrame(kcpInputBuf_.data(), static_cast<size_t>(n), 0);",
        "+        }",
        "+        peekSize = (!isServer_ && clientKcp_) ? clientKcp_->PeekSize() : kcp_->PeekSize();",
        "+    }",
        "+}",
