    return ids;
}

std::vector<NetEndpoint> NetworkLayer::GetAllClientEndpoints() const {
    std::vector<NetEndpoint> eps;
    for (auto& [id, ep] : playerIdToEndpoint_) {
        eps.push_back(ep);
