    return eps;
}

uint32_t NetworkLayer::GetEndpointKey(const NetEndpoint& ep) const {
    return (static_cast<uint32_t>(ep.address[0]) << 24) |
           (static_cast<uint32_t>(ep.address[1]) << 16) |
           (static_cast<uint32_t>(ep.address[2]) << 8) |
