        "+bool NetworkLayer::CreateAsServer(const char* addr, uint16_t port) {",
        "+    isServer_ = true;",
        "+    if (!udp_.Create()) return false;",
        "+    NetEndpoint bindAddr = NetEndpoint::Any(port);",
        "+    if (addr && strcmp(addr, "0.0.0.0") != 0) {",
        "+        ParseEndpoint(addr, port, &bindAddr);",
