        "+// -- Internal helpers --",
        "+",
        "+void NetworkLayer::SendUDP(const uint8_t* data, int size, const NetEndpoint& target) {",
        "+    if (!udp_ || size <= 0) return;",
        "+    int sent = udp_.SendTo(data, size, target);",
        "+    if (sent > 0) bytesSent_ += static_cast<uint64_t>(sent);",
