        "+void NetworkLayer::CheckHeartbeatTimeout() {",
        "+    uint64_t now = NowTickMS();",
        "+    if (lastRcvTimeTick_ > 0) {",
        "+        float elapsed = static_cast<float>(now - lastRcvTimeTick_);",
        "+        if (elapsed > HEARTBEAT_TIMEOUT_S * 1000.0f) {",
        "+            connected_.store(false);",
